// Determine which quarter to report on
const webhookData = $input.first().json.body || $input.first().json;
let quarter, fiscalYear, quarterStart, quarterEnd, previousQuarter, previousFiscalYear;

if (webhookData.quarter && webhookData.fiscal_year) {
  // Manual override
  quarter = webhookData.quarter;
  fiscalYear = Number(webhookData.fiscal_year);
} else {
  // Auto-detect: report on PREVIOUS quarter
  const now = new Date();
  const currentMonth = now.getMonth(); // 0-indexed
  const currentYear = now.getFullYear();
  const currentQ = Math.floor(currentMonth / 3) + 1;

  // Previous quarter
  let prevQ = currentQ - 1;
  let prevYear = currentYear;
  if (prevQ === 0) {
    prevQ = 4;
    prevYear = currentYear - 1;
  }
  quarter = 'Q' + prevQ;
  fiscalYear = prevYear;
}

// Calculate quarter date boundaries
const qNum = parseInt(quarter.replace('Q', ''));
const startMonth = (qNum - 1) * 3; // 0-indexed: Q1=0, Q2=3, Q3=6, Q4=9
quarterStart = fiscalYear + '-' + String(startMonth + 1).padStart(2, '0') + '-01';

// End of quarter: last day of the 3rd month
const endMonth = startMonth + 3; // next quarter start month (0-indexed)
const lastDay = new Date(fiscalYear, endMonth, 0).getDate();
quarterEnd = fiscalYear + '-' + String(startMonth + 3).padStart(2, '0') + '-' + String(lastDay).padStart(2, '0');

// Previous quarter for SCRB-05 review lookup
let prevQNum = qNum - 1;
let prevFY = fiscalYear;
if (prevQNum === 0) {
  prevQNum = 4;
  prevFY = fiscalYear - 1;
}
previousQuarter = 'Q' + prevQNum;
previousFiscalYear = prevFY;

return [{
  json: {
    quarter,
    fiscalYear,
    quarterStart,
    quarterEnd,
    previousQuarter,
    previousFiscalYear
  }
}];

const quarterData = $('Determine Quarter').first().json;
const droneJobs = $('Query drone_jobs').first().json;
const decisions = $('Query governance_decisions').first().json;
const obligations = $('Query compliance_obligations').first().json;
const financials = $('Query financial_actuals').first().json;
const govLog = $('Query governance_log').first().json;
const prevScribe = $('Query previous scribe output').first().json;

// Handle Supabase REST responses (arrays)
const droneJobsArr = Array.isArray(droneJobs) ? droneJobs : [];
const decisionsArr = Array.isArray(decisions) ? decisions : [];
const obligationsArr = Array.isArray(obligations) ? obligations : [];
const financialsArr = Array.isArray(financials) ? financials : [];
const govLogArr = Array.isArray(govLog) ? govLog : [];
const prevScribeArr = Array.isArray(prevScribe) ? prevScribe : [];

return [{
  json: {
    quarter: quarterData.quarter,
    fiscalYear: quarterData.fiscalYear,
    quarterStart: quarterData.quarterStart,
    quarterEnd: quarterData.quarterEnd,
    collectedData: {
      drone_jobs: droneJobsArr,
      governance_decisions: decisionsArr,
      compliance_obligations: obligationsArr,
      financial_actuals: financialsArr,
      governance_log: govLogArr,
      previous_scribe_output: prevScribeArr.length > 0 ? prevScribeArr[0] : null
    }
  }
}];

const response = $json;
const mergeData = $('Merge Data').first().json;

let minutes;
try {
  let text = response.content[0].text.trim();
  // Strip markdown code fences if present
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
  }
  minutes = JSON.parse(text);
} catch (e) {
  const raw = response.content ? response.content[0].text.substring(0, 200) : 'No content';
  throw new Error('Failed to parse Claude response as JSON: ' + e.message + '. First 200 chars: ' + raw);
}

// Validate all 8 required keys
const required = ['call_to_order', 'previous_quarter_review', 'financial_report', 'operations_report', 'compliance_report', 'decisions_and_resolutions', 'action_items', 'adjournment'];
const missing = required.filter(k => !minutes[k]);
if (missing.length > 0) {
  throw new Error('Missing required sections: ' + missing.join(', '));
}

return [{
  json: {
    quarter: mergeData.quarter,
    fiscalYear: mergeData.fiscalYear,
    quarterStart: mergeData.quarterStart,
    quarterEnd: mergeData.quarterEnd,
    minutes: minutes,
    collectedData: mergeData.collectedData
  }
}];

const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType } = require('docx');

const { quarter, fiscalYear, minutes } = $json;
const children = [];

// Title block
children.push(new Paragraph({ text: 'Faith & Harmony LLC', heading: HeadingLevel.TITLE, alignment: AlignmentType.CENTER }));
children.push(new Paragraph({ text: 'Quarterly Governance Meeting Minutes', heading: HeadingLevel.HEADING_1, alignment: AlignmentType.CENTER }));
children.push(new Paragraph({ text: quarter + ' ' + fiscalYear, heading: HeadingLevel.HEADING_2, alignment: AlignmentType.CENTER }));
children.push(new Paragraph({ text: '' }));

// Helper: add paragraphs from text or array
function addText(text) {
  if (!text) return;
  const parts = String(text).split('\n\n');
  for (const p of parts) {
    if (p.trim()) children.push(new Paragraph({ text: p.trim() }));
  }
}

function addBullets(items) {
  if (!items || !Array.isArray(items) || items.length === 0) {
    children.push(new Paragraph({ text: 'No items reported.' }));
    return;
  }
  for (const item of items) {
    children.push(new Paragraph({ text: typeof item === 'string' ? item : JSON.stringify(item), bullet: { level: 0 } }));
  }
}

// Section 1: Call to Order
children.push(new Paragraph({ text: '1. Call to Order', heading: HeadingLevel.HEADING_2 }));
const cto = minutes.call_to_order || {};
children.push(new Paragraph({ text: 'Date: ' + (cto.date || 'Not specified') }));
children.push(new Paragraph({ text: 'Time: ' + (cto.time || '9:00 AM ET') }));
children.push(new Paragraph({ text: 'Attendees: ' + (cto.attendees ? cto.attendees.join(', ') : 'Dradamo Pierce, Sole Member') }));
children.push(new Paragraph({ text: cto.quorum_statement || 'Sole member present constitutes quorum.' }));
children.push(new Paragraph({ text: '' }));

// Section 2: Previous Quarter Review
children.push(new Paragraph({ text: '2. Review of Previous Quarter', heading: HeadingLevel.HEADING_2 }));
const pqr = minutes.previous_quarter_review || {};
addText(pqr.summary || 'No prior quarter data available. This is the inaugural meeting.');
if (pqr.action_items && pqr.action_items.length > 0) {
  children.push(new Paragraph({ text: '' }));
  for (const ai of pqr.action_items) {
    children.push(new Paragraph({
      children: [
        new TextRun({ text: (ai.item || 'Item') + ' ', bold: true }),
        new TextRun({ text: '[' + (ai.status || 'unknown') + '] ' + (ai.notes || '') })
      ],
      bullet: { level: 0 }
    }));
  }
}
children.push(new Paragraph({ text: '' }));

// Section 3: Financial Report
children.push(new Paragraph({ text: '3. Financial Report', heading: HeadingLevel.HEADING_2 }));
const fin = minutes.financial_report || {};
addText(fin.revenue_summary || 'No revenue data reported.');
addText(fin.expense_summary || 'No expense data reported.');
addText(fin.cash_position || '');
if (fin.notable_variances && fin.notable_variances.length > 0) {
  children.push(new Paragraph({ children: [new TextRun({ text: 'Notable Variances:', bold: true })] }));
  addBullets(fin.notable_variances);
}
children.push(new Paragraph({ text: '' }));

// Section 4: Operations Report
children.push(new Paragraph({ text: '4. Operations Report', heading: HeadingLevel.HEADING_2 }));
const ops = minutes.operations_report || {};
addText(ops.jobs_summary || 'No operations data reported.');
addText(ops.package_mix || '');
addText(ops.equipment_status || '');
addText(ops.platform_updates || '');
children.push(new Paragraph({ text: '' }));

// Section 5: Compliance Report
children.push(new Paragraph({ text: '5. Compliance Report', heading: HeadingLevel.HEADING_2 }));
const comp = minutes.compliance_report || {};
addText(comp.summary || 'No compliance activity reported.');
if (comp.completed && comp.completed.length > 0) {
  children.push(new Paragraph({ children: [new TextRun({ text: 'Completed:', bold: true })] }));
  addBullets(comp.completed);
}
if (comp.approaching && comp.approaching.length > 0) {
  children.push(new Paragraph({ children: [new TextRun({ text: 'Approaching Deadlines:', bold: true })] }));
  addBullets(comp.approaching);
}
if (comp.overdue && comp.overdue.length > 0) {
  children.push(new Paragraph({ children: [new TextRun({ text: 'Overdue:', bold: true })] }));
  addBullets(comp.overdue);
}
children.push(new Paragraph({ text: '' }));

// Section 6: Decisions and Resolutions
children.push(new Paragraph({ text: '6. Decisions and Resolutions', heading: HeadingLevel.HEADING_2 }));
const resolutions = minutes.decisions_and_resolutions || [];
if (resolutions.length === 0) {
  children.push(new Paragraph({ text: 'No formal resolutions recorded this quarter.' }));
} else {
  for (const res of resolutions) {
    children.push(new Paragraph({ children: [new TextRun({ text: (res.reference || 'RES') + ': ' + (res.title || 'Untitled'), bold: true })] }));
    addText(res.context || '');
    addText(res.resolution || '');
    children.push(new Paragraph({ text: '' }));
  }
}
children.push(new Paragraph({ text: '' }));

// Section 7: Action Items
children.push(new Paragraph({ text: '7. Action Items', heading: HeadingLevel.HEADING_2 }));
const actions = minutes.action_items || [];
if (actions.length === 0) {
  children.push(new Paragraph({ text: 'No action items assigned.' }));
} else {
  for (const ai of actions) {
    children.push(new Paragraph({
      children: [
        new TextRun({ text: (ai.item || 'Item'), bold: true }),
        new TextRun({ text: ' | Owner: ' + (ai.owner || 'Unassigned') + ' | Due: ' + (ai.due_date || 'TBD') })
      ],
      bullet: { level: 0 }
    }));
  }
}
children.push(new Paragraph({ text: '' }));

// Section 8: Adjournment
children.push(new Paragraph({ text: '8. Adjournment', heading: HeadingLevel.HEADING_2 }));
const adj = minutes.adjournment || {};
children.push(new Paragraph({ text: 'Next Meeting: ' + (adj.next_meeting_date || 'To be determined') }));
addText(adj.closing_statement || 'Meeting adjourned.');
children.push(new Paragraph({ text: '' }));

// Footer
children.push(new Paragraph({
  children: [new TextRun({ text: 'Minutes prepared by Governance Scribe Agent | Generated ' + new Date().toISOString().slice(0, 10), italics: true })],
  alignment: AlignmentType.RIGHT
}));

const doc = new Document({ sections: [{ children }] });
const buffer = await Packer.toBuffer(doc);
const filename = fiscalYear + '-' + quarter + '_meeting_minutes.docx';
const storagePath = 'governance/scribe/' + filename;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(buffer),
  filename,
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
);

return [{
  json: {
    filename,
    storagePath,
    quarter: $json.quarter,
    fiscalYear: $json.fiscalYear,
    minutes: $json.minutes,
    collectedData: $json.collectedData
  },
  binary: { data: binaryData }
}];
